<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8" />
<title>Falling Sand</title>
<style>
  body {
    background: #121212;
    color: #e0e0e0;
    font-family: Roboto, sans-serif;
    margin: 0;
    padding: 20px;
    display: flex;
    flex-direction: column;
    align-items: center;
    min-height: 100vh;
  }
  .container {
    display: flex;
    gap: 20px;
    align-items: flex-start;
  }
  #sand {
    background: #1e1e1e;
    border: 1px solid #424242;
    cursor: crosshair;
  }
  .controls {
    display: flex;
    flex-direction: column;
    gap: 8px;
  }
  button {
    padding: 8px 16px;
    background: #3c3c3c;
    color: white;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    transition: background 0.2s;
  }
  button:hover {
    background: #5a5a5a;
  }
</style>
</head>
<body>
<div class="container">
<canvas id="sand" width="400" height="400"></canvas>
<div class="controls">
<button id="mat-sand">Sand</button>
<button id="mat-water">Water</button>
<button id="mat-wall">Wall</button>
<button id="mat-acid">Acid</button>
<button id="mat-empty">Eraser</button>
<button id="clear">Clear</button>
</div>
</div>

<script>
const canvas = document.getElementById('sand');
const ctx = canvas.getContext('2d');
const W = 80, H = 80;
const CELL = Math.floor(canvas.width / W);
let grid = Array(H).fill().map(() => Array(W).fill('empty'));
let selectedMat = 'sand';
let isPainting = false;

// Material colors
const colors = {
  empty: '#1e1e1e',
  sand: '#ffd700',
  water: '#42a5f5',
  wall: '#8d6e63',
  acid: '#00e676'
};

// Draw grid
function draw() {
  ctx.fillStyle = colors.empty;
  ctx.fillRect(0, 0, canvas.width, canvas.height);
  for (let y = 0; y < H; y++) {
    for (let x = 0; x < W; x++) {
      if (grid[y][x] !== 'empty') {
        ctx.fillStyle = colors[grid[y][x]];
        ctx.fillRect(x * CELL, y * CELL, CELL, CELL);
      }
    }
  }
}

// Convert canvas coordinates to grid
function canvasToGrid(cx, cy) {
  const x = Math.floor(cx / CELL);
  const y = Math.floor(cy / CELL);
  return { x: Math.max(0, Math.min(W - 1, x)), y: Math.max(0, Math.min(H - 1, y)) };
}

// Painting
canvas.addEventListener('mousedown', () => isPainting = true);
canvas.addEventListener('mouseup', () => isPainting = false);
canvas.addEventListener('mousemove', (e) => {
  if (!isPainting) return;
  const rect = canvas.getBoundingClientRect();
  const { x, y } = canvasToGrid(e.clientX - rect.left, e.clientY - rect.top);
  grid[y][x] = selectedMat;
  draw();
});

// Material buttons
document.getElementById('mat-sand').addEventListener('click', () => selectedMat = 'sand');
document.getElementById('mat-water').addEventListener('click', () => selectedMat = 'water');
document.getElementById('mat-wall').addEventListener('click', () => selectedMat = 'wall');
document.getElementById('mat-acid').addEventListener('click', () => selectedMat = 'acid');
document.getElementById('mat-empty').addEventListener('click', () => selectedMat = 'empty');
document.getElementById('clear').addEventListener('click', () => {
  grid = Array(H).fill().map(() => Array(W).fill('empty'));
  draw();
});

// Simulation functions
function get(x, y) { return grid[y][x]; }
function set(x, y, mat) { grid[y][x] = mat; }
function clear() { grid = Array(H).fill().map(() => Array(W).fill('empty')); }

function tick(n) {
  for (let step = 0; step < n; step++) {
    // Process bottom-up
    for (let y = H - 1; y >= 0; y--) {
      for (let x = 0; x < W; x++) {
        const mat = grid[y][x];
        if (mat === 'empty') continue;
        if (mat === 'wall') continue;

        let moved = false;
        // Fall down
        if (y + 1 < H && get(x, y + 1) === 'empty') {
          set(x, y + 1, mat);
          set(x, y, 'empty');
          moved = true;
        } else if (mat === 'sand' || mat === 'water' || mat === 'acid') {
          // Try diagonal moves
          const dirs = [[-1, 1], [1, 1]];
          for (let i of [0, 1]) {
            const nx = x + dirs[i][0];
            const ny = y + dirs[i][1];
            if (nx >= 0 && nx < W && ny < H && get(nx, ny) === 'empty') {
              set(nx, ny, mat);
              set(x, y, 'empty');
              moved = true;
              break;
            }
          }
        }

        // Water/acid spread horizontally
        if (!moved && (mat === 'water' || mat === 'acid')) {
          const dirs = [[-1, 0], [1, 0]];
          for (let i of [0, 1]) {
            const nx = x + dirs[i][0];
            if (nx >= 0 && nx < W && get(nx, y) === 'empty') {
              set(nx, y, mat);
              set(x, y, 'empty');
              moved = true;
              break;
            }
          }
        }

        // Acid dissolves
        if (!moved && mat === 'acid') {
          const dirs = [[0, 1], [-1, 0], [1, 0]];
          for (const [dx, dy] of dirs) {
            const nx = x + dx;
            const ny = y + dy;
            if (nx >= 0 && nx < W && ny >= 0 && ny < H) {
              const target = get(nx, ny);
              if (target === 'sand' || target === 'wall') {
                set(nx, ny, 'empty');
                moved = true; // optional: remove acid too
                break;
              }
            }
          }
        }
      }
    }
  }
  draw();
}

// Animation loop
let lastTime = 0;
function animate(t) {
  if (t - lastTime >= 16) { // ~60fps
    tick(1);
    lastTime = t;
  }
  requestAnimationFrame(animate);
}
requestAnimationFrame(animate);

// Expose API
window.sim = { w: W, h: H, tick, get, set, clear };

// Initial draw
draw();
</script>
</body>
</html>
